{
  "grammar": [
    {
      "pattern": "Subject + 喜歡 / 不喜歡 + Object",
      "structure": ["Subject", "喜歡/不喜歡", "Object"],
      "explanation_en": "Use 喜歡 to express liking and 不喜歡 to express disliking. The object can be a noun or a verb phrase.",
      "title": "Expressing Likes and Dislikes with 喜歡 and 不喜歡",
      "meaning": "To say you like or dislike something.",
      "when_to_use": [
        "When stating a preference for food, drinks, activities, or people.",
        "When answering a question about what you like."
      ],
      "when_not_to_use": [
        "Do not use 不喜歡 for temporary states like being full or tired.",
        "Do not use 喜歡 for things you need or have to do."
      ],
      "pragmatic_notes": "In Taiwan, 喜歡 is common in casual conversation. For polite refusals, use 還好 or 不太喜歡 instead of 不喜歡.",
      "word_order_notes": "Subject always comes first, followed by 喜歡/不喜歡, then the object.",
      "english_contrast": "English uses 'like' and 'don't like' similarly, but Chinese does not require an auxiliary verb like 'do' for negation.",
      "korean_contrast": "Korean uses 좋아하다/싫어하다 with object particle 을/를, while Chinese uses no particle.",
      "negative_examples": [
        {
          "text": "我喜歡不咖啡。",
          "error": "Negation 不 must come before 喜歡, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喜歡不咖啡。",
          "error": "Negation 不 must come before 喜歡, not after."
        }
      ],
      "transformation_drills": [
        "Change '我喜歡咖啡' to negative.",
        "Change '他不喜歡看電影' to affirmative."
      ],
      "production_drills": [
        "Say you like tea.",
        "Say you don't like spicy food."
      ],
      "common_error_patterns": [
        "Placing 不 after 喜歡 instead of before.",
        "Using 不喜歡 for temporary states."
      ],
      "repair_feedback": {
        "word_order": "Put 不 directly before 喜歡.",
        "politeness": "Use 還好 for polite dislike.",
        "vocabulary": "Use 不喜歡 only for stable dislikes."
      }
    },
    {
      "pattern": "Subject + 比較喜歡 + Object1 + 還是 + Object2",
      "structure": ["Subject", "比較喜歡", "Object1", "還是", "Object2"],
      "explanation_en": "Use 比較喜歡 to express a preference between two options, and 還是 to ask which one is preferred.",
      "title": "Expressing Preferences with 比較喜歡 and 還是",
      "meaning": "To say you prefer one thing over another or to ask about preferences.",
      "when_to_use": [
        "When comparing two items, activities, or choices.",
        "When asking someone to choose between two options."
      ],
      "when_not_to_use": [
        "Do not use 比較喜歡 for more than two options; use 最喜歡 instead.",
        "Do not use 還是 for open-ended questions; use 什麼 or 哪一個."
      ],
      "pragmatic_notes": "In Taiwan, 比較喜歡 is common in casual conversation. 還是 is specifically for choices, not for 'or' in statements.",
      "word_order_notes": "Subject first, then 比較喜歡, then the first option, 還是, then the second option.",
      "english_contrast": "English uses 'prefer A or B', while Chinese uses 比較喜歡 A 還是 B.",
      "korean_contrast": "Korean uses A랑 B 중에 뭐를 더 좋아해요? which is longer; Chinese is more direct.",
      "negative_examples": [
        {
          "text": "我比較喜歡咖啡或者茶。",
          "error": "Use 還是 for questions, not 或者."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我比較喜歡咖啡或者茶。",
          "error": "Use 還是 for questions, not 或者."
        }
      ],
      "transformation_drills": [
        "Change '你喜歡咖啡還是茶？' to use 比較喜歡.",
        "Answer '我比較喜歡茶' to the above question."
      ],
      "production_drills": [
        "Ask a friend if they prefer sweet or salty food.",
        "Say you prefer quiet places over noisy ones."
      ],
      "common_error_patterns": [
        "Using 或者 instead of 還是 in questions.",
        "Using 比較喜歡 for more than two options."
      ],
      "repair_feedback": {
        "word_order": "Keep 比較喜歡 before the options.",
        "politeness": "Use 比較喜歡 for polite preference.",
        "vocabulary": "Use 還是 only for questions with choices."
      }
    },
    {
      "pattern": "Subject + 喜歡 + Object1 + 還是 + Object2 (choice question) / Subject + Object1 + 或者 + Object2 (statement)",
      "structure": ["Subject", "喜歡/不喜歡", "Object1", "還是/或者", "Object2"],
      "explanation_en": "Use 還是 for questions asking which one is preferred; use 或者 for statements listing options without preference.",
      "title": "Distinguishing 還是 (Choice Question) and 或者 (Statement)",
      "meaning": "To ask about choices or list options.",
      "when_to_use": [
        "Use 還是 when asking someone to choose between options.",
        "Use 或者 when stating that either option is possible."
      ],
      "when_not_to_use": [
        "Do not use 還是 in statements.",
        "Do not use 或者 in questions."
      ],
      "pragmatic_notes": "In Taiwan, 還是 is very common in daily conversation for choices. 或者 is used in more neutral or formal contexts.",
      "word_order_notes": "In questions, 還是 connects the two options. In statements, 或者 connects them.",
      "english_contrast": "English uses 'or' for both questions and statements, but Chinese distinguishes them.",
      "korean_contrast": "Korean uses (이)나 for 'or' in statements and (이)랑 for choices, similar to Chinese distinction.",
      "negative_examples": [
        {
          "text": "你喜歡咖啡或者茶？",
          "error": "Use 還是 for questions, not 或者."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你喜歡咖啡或者茶？",
          "error": "Use 還是 for questions, not 或者."
        }
      ],
      "transformation_drills": [
        "Change '你喜歡咖啡還是茶？' to a statement using 或者.",
        "Change '我可以喝咖啡或者茶' to a question using 還是."
      ],
      "production_drills": [
        "Ask if your friend prefers sweet or salty snacks.",
        "Say you can eat either rice or noodles."
      ],
      "common_error_patterns": [
        "Using 或者 in questions.",
        "Using 還是 in statements."
      ],
      "repair_feedback": {
        "word_order": "Place 還是/或者 between the two options.",
        "politeness": "Use 還是 for polite questions.",
        "vocabulary": "Remember: 還是 for questions, 或者 for statements."
      }
    }
  ]
}
